# @cctt_verify {"v":2,"sym":"sympy.core.tests.test_args._test_args","kind":"function","src_hash":"3215fc302ee3100e","in":{"base":"Any","pred":"isinstance(arg, Basic)"},"out":{"base":"Any"},"spec":{"lhs":"_test_args(obj)","rhs":"internal helper behaves correctly","over":{"base":"Any","pred":"isinstance(arg, Basic)"},"name":"_test_args_correct"},"guarantee":"internal helper behaves correctly","fibers":[{"name":"Basic","pred":"isinstance(arg, Basic)","path":{"lhs":"_test_args(x)","rhs":"internal helper behaves correctly","over":{"base":"Basic","pred":"isinstance(arg, Basic)"},"name":"_test_args_Basic_case"},"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.tests.test_args._test_args_Basic_correct","statement":"_test_args satisfies spec on Basic inputs"},"trust":"LIBRARY"}],"h1":0,"paths":[],"strategy":"refinement_descent","details":{"exhaustiveness":"z3_proved","n_fibers":1,"h1":0},"assumes":[],"trust":["lean.C4.Descent.descent_soundness","z3.Solver.check"],"compiled":true,"vhash":"e293b41898a4b5a1"}
def _test_args(obj):
    all_basic = all(isinstance(arg, Basic) for arg in obj.args)
    # Ideally obj.func(*obj.args) would always recreate the object, but for
    # now, we only require it for objects with non-empty .args
    recreatable = not obj.args or obj.func(*obj.args) == obj
    return all_basic and recreatable


